const listActiveRecoveryCodes = `-- name: ListActiveRecoveryCodes :many
SELECT id, user_id, code_hash, used_at, created_at
FROM user_recovery_codes
WHERE user_id = $1
  AND used_at IS NULL
ORDER BY created_at ASC, id ASC
`

// All unused recovery codes for a user (used_at IS NULL).
// Ordered by created_at ASC, id ASC for stable pagination.
func (q *Queries) ListActiveRecoveryCodes(ctx context.Context, userID uuid.UUID) ([]UserRecoveryCode, error) {
	rows, err := q.db.Query(ctx, listActiveRecoveryCodes, userID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []UserRecoveryCode
	for rows.Next() {
		var i UserRecoveryCode
		if err := rows.Scan(
			&i.ID,
			&i.UserID,
			&i.CodeHash,
			&i.UsedAt,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

